class Solution:
    def carPooling(self, trips, capacity):
        points = set()
        for _, a, b in trips:
            points.add(a)
            points.add(b)
        for loc in sorted(points):
            onboard = 0
            for p, a, b in trips:
                if a <= loc < b:
                    onboard += p
            if onboard > capacity:
                return False
        return True

