class Solution:
    def carPooling(self, trips, capacity):
        timeline = [0] * 1001
        for p, a, b in trips:
            timeline[a] += p
            timeline[b] -= p
        cur = 0
        for delta in timeline:
            cur += delta
            if cur > capacity:
                return False
        return True

