var carPooling = function(trips, capacity) {
    const timeline = new Array(1001).fill(0);
    for (const [p, a, b] of trips) {
        timeline[a] += p;
        timeline[b] -= p;
    }
    let cur = 0;
    for (const delta of timeline) {
        cur += delta;
        if (cur > capacity) return false;
    }
    return true;
};
